sql:
SELECT AVG(grade) AS average_grade
FROM grade_records
WHERE course_id = 1;

SELECT course_name 
FROM courses 
ORDER BY course_name;

SELECT AVG(rating) AS average_rating
FROM course_evaluations
WHERE course_id = 0;

SELECT MAX(grade) AS highest_grade
FROM grade_records
WHERE course_id = 1;

